public class PlusDemo {
    public static void main(String[] args) {
        // Case 1: Both numbers first
        System.out.println(1 + 2 + " Hello");   // "3 Hello"  (1+2=3, then 3+" Hello")

        // Case 2: String first
        System.out.println("Hello " + 1 + 2);   // "Hello 12" ("Hello"+1="Hello 1", then+2)

        // Case 3: Parentheses force arithmetic
        System.out.println("Sum: " + (1 + 2));   // "Sum: 3"

        // Case 4: char + int = int!
        System.out.println('A' + 1);             // 66  (not "A1")
        System.out.println("" + 'A' + 1);        // "A1" (string context)
    }
}

public class DivisionDemo {
    public static void main(String[] args) {
        System.out.println(7 / 2);       // 3    (integer division, truncates)
        System.out.println(7.0 / 2);     // 3.5  (double promoted)
        System.out.println(7 / 2.0);     // 3.5  (double promoted)
        System.out.println((double)7/2); // 3.5  (explicit cast first)
        System.out.println(7 % 2);       // 1    (remainder/modulus)
        System.out.println(-7 % 2);      // -1   (sign follows dividend!)

        int a = 5, b = 2;
        double result = a / b;            // STILL 2.0! Division happens first
        System.out.println(result);       // 2.0  (not 2.5)
    }
}

public class IncrementDemo {
    public static void main(String[] args) {
        int x = 5;
        System.out.println(x++);   // prints 5, then x becomes 6
        System.out.println(x);     // prints 6
        System.out.println(++x);   // x becomes 7, then prints 7
        System.out.println(x);     // prints 7

        int a = 3;
        int b = a++ + ++a;         // a++ uses 3 (a becomes 4), ++a uses 5 (a becomes 5)
        System.out.println(b);     // 3 + 5 = 8
        System.out.println(a);     // 5
    }
}

public class PrintfDemo {
    public static void main(String[] args) {
        printf("Name: %s, Age: %d%n", "Ashik", 20);  // Name: Ashik, Age: 20
        printf("Pi = %.4f%n", Math.PI);              // Pi = 3.1416
        printf("|%10s|%n", "hi");                    // |        hi|
        printf("%-10s|%n", "hi");                    // |hi        |
        printf("%05d%n", 42);                        // 00042
    }
    // shorthand — in a real program: System.out.printf()
    static java.io.PrintStream printf = System.out;
}

