        System.out.println(x);
    }
}

public class Q3 {
    public static void main(String[] args) {
        int a = 10, b = 3;
        System.out.println(a / b);
        System.out.println(a % b);
        System.out.println((double) a / b);
        System.out.println(a / (double) b);
        double result = a / b;
        System.out.println(result);
    }
}

