public class Q6 {
    public static void main(String[] args) {
        double d = 9.99;
        int i = (int) d;
        System.out.println(i);                  // Line A
        System.out.println((int)(3.9 + 4.9));   // Line B
        System.out.println((int) 3.9 + (int) 4.9); // Line C
        byte b = (byte) 200;
        System.out.println(b);                  // Line D
    }
}
